     1→// ============================================================================
     2→// API ROUTE: Chat completions
     3→// Supports: Azure OpenAI, Ollama (local)
     4→// NEVER: Direct OpenAI API, Anthropic
     5→// SECURITY: Input/output filtering for child safety (Issue #30)
     6→// FEATURE: Function calling for tool execution (Issue #39)
     7→// ============================================================================
     8→
     9→import { NextRequest, NextResponse } from 'next/server';
    10→import { cookies } from 'next/headers';
    11→import { chatCompletion, getActiveProvider, type AIProvider } from '@/lib/ai/providers';
    12→import { prisma } from '@/lib/db';
    13→import { logger } from '@/lib/logger';
    14→import { checkRateLimit, getClientIdentifier, RATE_LIMITS, rateLimitResponse } from '@/lib/rate-limit';
    15→import { filterInput, sanitizeOutput } from '@/lib/safety';
    16→import { CHAT_TOOL_DEFINITIONS } from '@/types/tools';
    17→import { executeToolCall } from '@/lib/tools/tool-executor';
    18→import { loadPreviousContext } from '@/lib/conversation/memory-loader';
    19→import { enhanceSystemPrompt } from '@/lib/conversation/prompt-enhancer';
    20→// Import handlers to register them
    21→import '@/lib/tools/handlers';
    22→
    23→interface ChatMessage {
    24→  role: 'user' | 'assistant' | 'system';
    25→  content: string;
    26→}
    27→
    28→interface ChatRequest {
    29→  messages: ChatMessage[];
    30→  systemPrompt: string;
    31→  maestroId: string;
    32→  enableTools?: boolean; // Optional: enable tool calling (default: true)
    33→  enableMemory?: boolean; // Optional: enable conversation memory (default: true)
    34→  requestedTool?: 'mindmap' | 'quiz' | 'flashcard' | 'demo' | 'summary'; // Tool context injection
    35→}
    36→
    37→// Tool context to inject into system prompt (Phase 5: Chat API Enhancement)
    38→const TOOL_CONTEXT: Record<string, string> = {
    39→  mindmap: `
    40→STAI CREANDO UNA MAPPA MENTALE con lo studente.
    41→Linee guida:
    42→- Fai domande maieutiche per esplorare l'argomento
    43→- Parti dal concetto centrale e espandi in modo organico
    44→- Usa create_mindmap per costruire la mappa incrementalmente
    45→- Ogni risposta dello studente può aggiungere nodi alla mappa
    46→- Mantieni la struttura chiara e gerarchica`,
    47→
    48→  quiz: `
    49→STAI CREANDO UN QUIZ con lo studente.
    50→
    51→**REGOLA IMPORTANTE:** Prima di creare il quiz, CHIEDI allo studente:
    52→"Preferisci fare il quiz per iscritto (lo vedi sullo schermo) oppure a voce (te lo faccio io)?"
    53→
    54→Se sceglie PER ISCRITTO:
    55→- Chiedi prima di che argomento vuole essere interrogato
    56→- Crea domande a scelta multipla chiare e formative
    57→- Usa create_quiz per generare il quiz
    58→- Includi feedback educativo per ogni risposta
    59→- Adatta la difficoltà al livello dello studente
    60→
    61→Se sceglie A VOCE (o se siete in una sessione vocale):
    62→- NON usare create_quiz!
    63→- Fai tu le domande una alla volta nella chat
    64→- Elenca le opzioni (A, B, C, D)
    65→- Aspetta la risposta dello studente
    66→- Conferma se è corretta o spiega perché è sbagliata
    67→- Passa alla domanda successiva
    68→- Alla fine dai un resoconto del punteggio`,
    69→
    70→  flashcard: `
    71→STAI CREANDO FLASHCARD per lo studente.
    72→Linee guida:
    73→- Identifica i concetti chiave da memorizzare
    74→- Crea carte con domanda/risposta brevi e incisive
    75→- Usa create_flashcards per generare le carte
    76→- Organizza le carte per argomento o difficoltà
    77→- Le flashcard verranno usate con ripetizione spaziata FSRS`,
    78→
    79→  demo: `
    80→STAI CREANDO UNA DEMO INTERATTIVA per lo studente.
    81→Linee guida:
    82→- Capisce cosa lo studente vuole visualizzare
    83→- Crea simulazioni semplici ma efficaci
    84→- Usa create_demo per generare la demo HTML/JS
    85→- Mantieni l'interattività intuitiva e accessibile
    86→- Spiega cosa la demo sta mostrando`,
    87→
    88→  summary: `
    89→STAI CREANDO UN RIASSUNTO STRUTTURATO con lo studente.
    90→Linee guida:
    91→- Chiedi prima quale argomento vuole riassumere
    92→- Organizza il contenuto in sezioni chiare e logiche
    93→- Usa create_summary per costruire il riassunto
    94→- Includi punti chiave per ogni sezione
    95→- Adatta la lunghezza alle esigenze dello studente (breve/medio/lungo)
    96→- Fai domande per approfondire i punti importanti`,
    97→};
    98→
    99→export async function POST(request: NextRequest) {
   100→  // Rate limiting: 20 requests per minute per IP
   101→  const clientId = getClientIdentifier(request);
   102→  const rateLimit = checkRateLimit(`chat:${clientId}`, RATE_LIMITS.CHAT);
   103→
   104→  if (!rateLimit.success) {
   105→    logger.warn('Rate limit exceeded', { clientId, endpoint: '/api/chat' });
   106→    return rateLimitResponse(rateLimit);
   107→  }
   108→
   109→  try {
   110→    const body: ChatRequest = await request.json();
   111→    const { messages, systemPrompt, maestroId, enableTools = true, enableMemory = true, requestedTool } = body;
   112→
   113→    if (!messages || !Array.isArray(messages)) {
   114→      return NextResponse.json(
   115→        { error: 'Messages array is required' },
   116→        { status: 400 }
   117→      );
   118→    }
   119→
   120→    // Get userId from cookie for memory injection and provider preference
   121→    const cookieStore = await cookies();
   122→    const userId = cookieStore.get('convergio-user-id')?.value;
   123→
   124→    // #87: Get user's provider preference from settings
   125→    let providerPreference: AIProvider | 'auto' | undefined;
   126→    if (userId) {
   127→      try {
   128→        const settings = await prisma.settings.findUnique({
   129→          where: { userId },
   130→          select: { provider: true },
   131→        });
   132→        if (settings?.provider && (settings.provider === 'azure' || settings.provider === 'ollama')) {
   133→          providerPreference = settings.provider;
   134→        }
   135→      } catch (e) {
   136→        // Settings lookup failure should not block chat
   137→        logger.debug('Failed to load provider preference', { error: String(e) });
   138→      }
   139→    }
   140→
   141→    // Build enhanced system prompt with tool context
   142→    let enhancedSystemPrompt = systemPrompt;
   143→    if (requestedTool && TOOL_CONTEXT[requestedTool]) {
   144→      enhancedSystemPrompt = `${systemPrompt}\n\n${TOOL_CONTEXT[requestedTool]}`;
   145→      logger.debug('Tool context injected', { requestedTool, maestroId });
   146→    }
   147→
   148→    // Inject conversation memory if enabled and user is authenticated (ADR 0021)
   149→    let hasMemory = false;
   150→    if (enableMemory && userId && maestroId) {
   151→      try {
   152→        const memory = await loadPreviousContext(userId, maestroId);
   153→        if (memory.recentSummary || memory.keyFacts.length > 0) {
   154→          enhancedSystemPrompt = enhanceSystemPrompt({
   155→            basePrompt: enhancedSystemPrompt,
   156→            memory,
   157→            safetyOptions: {
   158→              role: 'maestro',
   159→            },
   160→          });
   161→          hasMemory = true;
   162→          logger.debug('Conversation memory injected', {
   163→            maestroId,
   164→            keyFactCount: memory.keyFacts.length,
   165→            hasSummary: !!memory.recentSummary,
   166→          });
   167→        }
   168→      } catch (memoryError) {
   169→        // Memory loading failure should not block the chat
   170→        logger.warn('Failed to load conversation memory', {
   171→          userId,
   172→          maestroId,
   173→          error: String(memoryError),
   174→        });
   175→      }
   176→    }
   177→
   178→    // SECURITY: Filter the last user message for safety (Issue #30)
   179→    const lastUserMessage = messages.filter(m => m.role === 'user').pop();
   180→    if (lastUserMessage) {
   181→      const filterResult = filterInput(lastUserMessage.content);
   182→      if (!filterResult.safe && filterResult.action === 'block') {
   183→        logger.warn('Content blocked by safety filter', {
   184→          clientId,
   185→          category: filterResult.category,
   186→          severity: filterResult.severity,
   187→        });
   188→        return NextResponse.json({
   189→          content: filterResult.suggestedResponse,
   190→          provider: 'safety_filter',
   191→          model: 'content-filter',
   192→          blocked: true,
   193→          category: filterResult.category,
   194→        });
   195→      }
   196→    }
   197→
   198→    // #87: Get active provider info for response (pass preference for consistency)
   199→    const providerConfig = getActiveProvider(providerPreference);
   200→
   201→    try {
   202→      // Call AI with optional tool definitions
   203→      // Cast to mutable array since chatCompletion expects ToolDefinition[]
   204→      // #87: Pass user's provider preference to chatCompletion
   205→      const result = await chatCompletion(messages, enhancedSystemPrompt, {
   206→        tools: enableTools ? ([...CHAT_TOOL_DEFINITIONS] as typeof CHAT_TOOL_DEFINITIONS[number][]) : undefined,
   207→        tool_choice: enableTools ? 'auto' : 'none',
   208→        providerPreference,
   209→      });
   210→
   211→      // Handle tool calls if present
   212→      if (result.tool_calls && result.tool_calls.length > 0) {
   213→        const toolResults = [];
   214→
   215→        for (const toolCall of result.tool_calls) {
   216→          try {
   217→            const args = JSON.parse(toolCall.function.arguments);
   218→            const toolResult = await executeToolCall(
   219→              toolCall.function.name,
   220→              args,
   221→              { maestroId, conversationId: undefined, userId }
   222→            );
   223→            // Transform to ToolCall interface format expected by ToolResultDisplay
   224→            // Note: type uses function name (e.g., 'create_mindmap') to match ToolType in types/index.ts
   225→            toolResults.push({
   226→              id: toolResult.toolId || toolCall.id,
   227→              type: toolCall.function.name,
   228→              name: toolCall.function.name,
   229→              arguments: args,
   230→              status: toolResult.success ? 'completed' : 'error',
   231→              result: {
   232→                success: toolResult.success,
   233→                data: toolResult.data,
   234→                error: toolResult.error,
   235→              },
   236→            });
   237→          } catch (toolError) {
   238→            logger.error('Tool execution failed', {
   239→              toolCall: toolCall.function.name,
   240→              error: String(toolError),
   241→            });
   242→            const args = JSON.parse(toolCall.function.arguments || '{}');
   243→            toolResults.push({
   244→              id: toolCall.id,
   245→              type: toolCall.function.name,
   246→              name: toolCall.function.name,
   247→              arguments: args,
   248→              status: 'error',
   249→              result: {
   250→                success: false,
   251→                error: toolError instanceof Error ? toolError.message : 'Tool execution failed',
   252→              },
   253→            });
   254→          }
   255→        }
   256→
   257→        // Return response with tool results
   258→        return NextResponse.json({
   259→          content: result.content || '',
   260→          provider: result.provider,
   261→          model: result.model,
   262→          usage: result.usage,
   263→          maestroId,
   264→          toolCalls: toolResults,
   265→          hasTools: true,
   266→          hasMemory,
   267→        });
   268→      }
   269→
   270→      // SECURITY: Sanitize AI output before returning (Issue #30)
   271→      const sanitized = sanitizeOutput(result.content);
   272→      if (sanitized.modified) {
   273→        logger.warn('Output sanitized', {
   274→          clientId,
   275→          issuesFound: sanitized.issuesFound,
   276→          categories: sanitized.categories,
   277→        });
   278→      }
   279→
   280→      return NextResponse.json({
   281→        content: sanitized.text,
   282→        provider: result.provider,
   283→        model: result.model,
   284→        usage: result.usage,
   285→        hasMemory,
   286→        maestroId,
   287→        sanitized: sanitized.modified,
   288→      });
   289→    } catch (providerError) {
   290→      // Provider-specific error handling
   291→      const errorMessage =
   292→        providerError instanceof Error
   293→          ? providerError.message
   294→          : 'Unknown provider error';
   295→
   296→      // Check if it's an Ollama availability issue
   297→      if (errorMessage.includes('Ollama is not running')) {
   298→        return NextResponse.json(
   299→          {
   300→            error: 'No AI provider available',
   301→            message: errorMessage,
   302→            help: 'Configure Azure OpenAI or start Ollama: ollama serve && ollama pull llama3.2',
   303→            provider: providerConfig?.provider ?? 'none',
   304→          },
   305→          { status: 503 }
   306→        );
   307→      }
   308→
   309→      return NextResponse.json(
   310→        {
   311→          error: 'Chat request failed',
   312→          message: errorMessage,
   313→          provider: providerConfig?.provider ?? 'unknown',
   314→        },
   315→        { status: 500 }
   316→      );
   317→    }
   318→  } catch (error) {
   319→    logger.error('Chat API error', { error: String(error) });
   320→    return NextResponse.json(
   321→      { error: 'Internal server error' },
   322→      { status: 500 }
   323→    );
   324→  }
   325→}
   326→
   327→// GET endpoint to check provider status
   328→export async function GET() {
   329→  const provider = getActiveProvider();
   330→
   331→  if (!provider) {
   332→    return NextResponse.json({
   333→      available: false,
   334→      provider: null,
   335→      message: 'No AI provider configured',
   336→    });
   337→  }
   338→
   339→  return NextResponse.json({
   340→    available: true,
   341→    provider: provider.provider,
   342→    model: provider.model,
   343→  });
   344→}
   345→

