   348→          english: 'inglese',
   349→          art: 'arte',
   350→          music: 'musica',
   351→        };
   352→        return subjectMap[subject] ?? 'other';
   353→      };
   354→
   355→      if (routingResult.intent.type === 'method_help' ||
   356→          routingResult.intent.type === 'emotional_support') {
   357→        // Student is seeking help - track as help request
   358→        const timeElapsed = Math.round((Date.now() - sessionStartTimeRef.current) / 1000);
   359→        methodProgressStore.recordHelpRequest(
   360→          routingResult.reason,
   361→          timeElapsed,
   362→          mapToMethodSubject(routingResult.intent.subject)
   363→        );
   364→      } else if (routingResult.intent.type === 'academic_help' &&
   365→                 activeCharacter?.type === 'maestro') {
   366→        // Student is working independently with a maestro
   367→        // Only track as "solved alone" if they've been working for a while
   368→        if (messages.length > 4) {
   369→          methodProgressStore.recordProblemSolvedAlone(
   370→            userMessage.slice(0, 100),
   371→            mapToMethodSubject(routingResult.intent.subject)
   372→          );
   373→        }
   374→      }
   375→
   376→      // Check if we should suggest a handoff
   377→      if (
   378→        routingResult.characterType !== activeCharacter.type &&
   379→        routingResult.intent.confidence >= 0.7
   380→      ) {
   381→        // High confidence different character needed - suggest handoff
   382→        const { getMaestroById: _getMaestroById } = await import('@/data/maestri');
   383→        const { getSupportTeacherById } = await import('@/data/support-teachers');
   384→        const { getBuddyById } = await import('@/data/buddy-profiles');
   385→
   386→        let targetCharacter;
   387→        switch (routingResult.characterType) {
   388→          case 'maestro':
   389→            targetCharacter = routingResult.character;
   390→            break;
   391→          case 'coach':
   392→            targetCharacter =
   393→              getSupportTeacherById(extendedProfile.preferredCoach || 'melissa') ||
   394→              routingResult.character;
   395→            break;
   396→          case 'buddy':
   397→            targetCharacter =
   398→              getBuddyById(extendedProfile.preferredBuddy || 'mario') ||
   399→              routingResult.character;
   400→            break;
   401→        }
   402→
   403→        if (targetCharacter && targetCharacter.id !== activeCharacter.id) {
   404→          // Create active character for handoff
   405→          const handoffCharacter = {
   406→            type: routingResult.characterType,
   407→            id: targetCharacter.id,
   408→            name: targetCharacter.name,
   409→            character: targetCharacter,
   410→            greeting:
   411→              routingResult.characterType === 'buddy' && 'getGreeting' in targetCharacter
   412→                ? (targetCharacter as { getGreeting: (p: ExtendedStudentProfile) => string }).getGreeting(extendedProfile)
   413→                : 'greeting' in targetCharacter ? String(targetCharacter.greeting) : '',
   414→            systemPrompt:
   415→              routingResult.characterType === 'buddy' && 'getSystemPrompt' in targetCharacter
   416→                ? (targetCharacter as { getSystemPrompt: (p: ExtendedStudentProfile) => string }).getSystemPrompt(extendedProfile)
   417→                : 'systemPrompt' in targetCharacter ? String(targetCharacter.systemPrompt) : '',
   418→            color: targetCharacter.color,
   419→            voice: 'voice' in targetCharacter ? targetCharacter.voice : 'alloy',
   420→            voiceInstructions: 'voiceInstructions' in targetCharacter ? targetCharacter.voiceInstructions : '',
   421→          };
   422→
   423→          // Suggest handoff instead of auto-switching
   424→          suggestHandoff({
   425→            toCharacter: handoffCharacter,
   426→            reason: routingResult.reason,
   427→            confidence: routingResult.intent.confidence,
   428→          });
   429→        }
   430→      }
   431→
   432→      // Send to AI for response with memory context (ADR 0021)
   433→      const response = await fetch('/api/chat', {
   434→        method: 'POST',
   435→        headers: { 'Content-Type': 'application/json' },
   436→        body: JSON.stringify({
   437→          messages: [
   438→            { role: 'system', content: activeCharacter.systemPrompt },
   439→            ...messages
   440→              .filter((m) => m.role !== 'system')
   441→              .map((m) => ({
   442→                role: m.role,
   443→                content: m.content,
   444→              })),
   445→            { role: 'user', content: userMessage },
   446→          ],
   447→          maestroId: activeCharacter.id,
   448→          enableMemory: true, // ADR 0021: Enable conversational memory injection
   449→        }),
   450→      });
   451→
   452→      if (!response.ok) {
   453→        throw new Error('Failed to get response');
   454→      }
   455→
   456→      const data = await response.json();
   457→      const assistantContent = data.content || data.message || '';
   458→      addMessage({ role: 'assistant', content: assistantContent });
   459→
   460→      // Also check AI response for handoff signals (reactive detection)
   461→      if (!pendingHandoff) {
   462→        const handoffAnalysis = analyzeHandoff({
   463→          message: userMessage,
   464→          aiResponse: assistantContent,
   465→          activeCharacter,
   466→          studentProfile: extendedProfile,
   467→          recentMessages: messages.slice(-5).map((m) => ({
   468→            role: m.role === 'system' ? 'assistant' : (m.role as 'user' | 'assistant'),
   469→            content: m.content,
   470→          })),
   471→        });
   472→
   473→        if (handoffAnalysis.shouldHandoff && handoffAnalysis.suggestion && handoffAnalysis.confidence > 0.7) {
   474→          suggestHandoff(handoffAnalysis.suggestion);
   475→        }
   476→      }
   477→    } catch (error) {
   478→      logger.error('Chat error', { error });
   479→      addMessage({
   480→        role: 'assistant',
   481→        content: 'Mi dispiace, ho avuto un problema. Puoi riprovare?',
   482→      });
   483→    } finally {
   484→      setIsLoading(false);
   485→    }
   486→  }, [
   487→    inputValue,
   488→    isLoading,
   489→    activeCharacter,
   490→    addMessage,
   491→    messages,
   492→    extendedProfile,
   493→    routeMessage,
   494→    suggestHandoff,
   495→    pendingHandoff,
   496→  ]);
   497→
   498→  /**
   499→   * Handle key press in input.
   500→   */
   501→  const handleKeyPress = (e: React.KeyboardEvent) => {
   502→    if (e.key === 'Enter' && !e.shiftKey) {
   503→      e.preventDefault();
   504→      handleSend();
   505→    }
   506→  };
   507→
   508→  /**
   509→   * Handle voice mode toggle (for input area).
   510→   */
   511→  const handleVoiceToggle = () => {
   512→    if (mode === 'voice') {
   513→      setMode('text');
   514→    } else {
   515→      setMode('voice');
   516→    }
   517→  };
   518→
   519→  /**
   520→   * Handle voice call (full voice conversation).
   521→   */
   522→  const handleVoiceCall = useCallback(() => {
   523→    if (isVoiceActive) {
   524→      // End voice call
   525→      setIsVoiceActive(false);
   526→      setMode('text');
   527→    } else {
   528→      // Start voice call
   529→      setIsVoiceActive(true);
   530→      setMode('voice');
   531→      // Voice session will be started by VoiceCallOverlay
   532→      // This is a placeholder - Issue #34 tracks voice WebSocket issues
   533→    }
   534→  }, [isVoiceActive, setMode]);
   535→
   536→  /**
   537→   * Handle accepting handoff.
   538→   */
   539→  const handleAcceptHandoff = () => {
   540→    acceptHandoff(extendedProfile);
   541→  };
   542→
   543→  /**
   544→   * Handle manual character switches.
   545→   */
   546→  const handleSwitchToCoach = () => switchToCoach(extendedProfile);
   547→  const handleSwitchToBuddy = () => switchToBuddy(extendedProfile);
   548→  const handleGoBack = () => goBack(extendedProfile);
   549→
   550→  // Render idle state (shouldn't happen with auto-start)
   551→  if (!isActive || !activeCharacter) {
   552→    return (
   553→      <div className="flex items-center justify-center h-full">
   554→        <Button onClick={() => startConversation(extendedProfile)}>
   555→          Inizia una conversazione
   556→        </Button>
   557→      </div>
   558→    );
   559→  }
   560→
   561→  // Video conference layout when tool is active (Issue #36)
   562→  const hasActiveTool = activeTool && activeTool.status !== 'error';
   563→
   564→  return (
   565→    <div className="relative flex flex-col h-[calc(100vh-200px)] max-h-[700px] bg-white dark:bg-slate-900 rounded-2xl shadow-xl overflow-hidden">
   566→      {/* Voice call overlay */}
   567→      <AnimatePresence>
   568→        {isVoiceActive && activeCharacter && (
   569→          <VoiceCallOverlay
   570→            character={activeCharacter}
   571→            onEnd={handleVoiceCall}
   572→            onSessionIdChange={setVoiceSessionId}
   573→          />
   574→        )}
   575→      </AnimatePresence>
   576→
   577→      {/* Header with character info and voice call button - 10% */}
   578→      <ConversationHeader
   579→        currentCharacter={activeCharacter}
   580→        onSwitchToCoach={handleSwitchToCoach}
   581→        onSwitchToBuddy={handleSwitchToBuddy}
   582→        onGoBack={handleGoBack}
   583→        canGoBack={characterHistory.length > 1}
   584→        isVoiceActive={isVoiceActive}
   585→        onVoiceCall={handleVoiceCall}
   586→      />
   587→
   588→      {/* Handoff suggestion */}
   589→      <AnimatePresence>
   590→        {pendingHandoff && (
   591→          <HandoffBanner
   592→            suggestion={pendingHandoff}
   593→            onAccept={handleAcceptHandoff}
   594→            onDismiss={dismissHandoff}
   595→          />
   596→        )}
   597→      </AnimatePresence>
   598→
   599→      {/* Main content area - switches between chat-first and tool-first layouts */}
   600→      {hasActiveTool ? (
   601→        /* VIDEO CONFERENCE LAYOUT: Tool takes center stage (Issue #36) */
   602→        <div className="flex-1 flex flex-col overflow-hidden">
   603→          {/* Tool panel - 70% of remaining space */}
   604→          <div className="flex-[7] overflow-auto border-b border-slate-200 dark:border-slate-700">
   605→            <ToolPanel
   606→              tool={activeTool}
   607→              maestro={activeCharacter ? {
   608→                name: activeCharacter.name,
   609→                avatar: CHARACTER_AVATARS[activeCharacter.id] || '/avatars/default.jpg',
   610→                color: activeCharacter.color,
   611→              } : null}
   612→              onClose={() => setActiveTool(null)}
   613→              isMinimized={isToolMinimized}
   614→              onToggleMinimize={() => setIsToolMinimized(!isToolMinimized)}
   615→              embedded={true}
   616→              sessionId={voiceSessionId}
   617→            />
   618→          </div>
   619→
   620→          {/* Mini chat - 15% of remaining space */}
   621→          <div
   622→            className="flex-[1.5] overflow-y-auto p-2 bg-slate-50 dark:bg-slate-800/50"
   623→            role="log"
   624→            aria-live="polite"
   625→            aria-label="Messaggi recenti"
   626→          >
   627→            {/* Show only last 3 messages in mini view */}
   628→            {messages.slice(-3).map((message) => (
   629→              <div
   630→                key={message.id}
   631→                className={cn(
   632→                  'text-xs py-1 px-2 rounded mb-1',
   633→                  message.role === 'user'
   634→                    ? 'bg-accent-themed/10 text-right'
   635→                    : 'bg-slate-200 dark:bg-slate-700'
   636→                )}
   637→              >
   638→                <span className="font-medium">
   639→                  {message.role === 'user' ? 'Tu' : activeCharacter?.name}:
   640→                </span>{' '}
   641→                {message.content.substring(0, 80)}
   642→                {message.content.length > 80 && '...'}
   643→              </div>
   644→            ))}
   645→            {isLoading && (
   646→              <div className="text-xs py-1 px-2 flex items-center gap-1">
   647→                <Loader2 className="w-3 h-3 animate-spin" />
   648→                <span>{activeCharacter?.name} sta pensando...</span>
   649→              </div>
   650→            )}
   651→          </div>
   652→        </div>
   653→      ) : (
   654→        /* NORMAL LAYOUT: Chat takes full space */
   655→        <div
   656→          className="flex-1 overflow-y-auto p-4"
   657→          role="log"
   658→          aria-live="polite"
   659→          aria-label="Messaggi della conversazione"
   660→        >
   661→          {messages.map((message) => (
   662→            <MessageBubble
   663→              key={message.id}
   664→              message={message}
   665→              activeCharacter={
   666→                message.role === 'assistant' ? activeCharacter : null
   667→              }
   668→            />
   669→          ))}
   670→          {isLoading && (
   671→            <motion.div
   672→              initial={{ opacity: 0 }}
   673→              animate={{ opacity: 1 }}
   674→              className="flex gap-3 mb-4"
   675→            >
   676→              <CharacterAvatar character={activeCharacter} size="sm" />
   677→              <div className="px-4 py-3 bg-slate-100 dark:bg-slate-800 rounded-2xl rounded-bl-md">
   678→                <Loader2 className="w-5 h-5 animate-spin text-slate-500" />
   679→              </div>
   680→            </motion.div>
   681→          )}
   682→          <div ref={messagesEndRef} />
   683→        </div>
   684→      )}
   685→
   686→      {/* Input area - 5% */}
   687→      <div className="p-4 border-t border-slate-200 dark:border-slate-700">
   688→        <div className="flex items-center gap-2">
   689→          {/* Tool buttons - quick access to educational tools */}
   690→          <ToolButtons
   691→            onToolRequest={handleToolRequest}
   692→            disabled={isLoading}
   693→            activeToolId={activeTool?.id}
   694→          />
   695→          <input
   696→            ref={inputRef}
   697→            type="text"
   698→            value={inputValue}
   699→            onChange={(e) => setInputValue(e.target.value)}
   700→            onKeyDown={handleKeyPress}
   701→            placeholder={`Scrivi a ${activeCharacter.name}...`}
   702→            aria-label={`Scrivi un messaggio a ${activeCharacter.name}`}
   703→            className="flex-1 px-4 py-3 bg-slate-100 dark:bg-slate-800 rounded-xl border-0 focus:ring-2 focus:ring-accent-themed outline-none text-slate-900 dark:text-white placeholder:text-slate-500"
   704→            disabled={isLoading}
   705→          />
   706→          <Button
   707→            variant="ghost"
   708→            size="icon"
   709→            onClick={() => setIsMuted(!isMuted)}
   710→            aria-label={isMuted ? 'Attiva audio' : 'Disattiva audio'}
   711→            aria-pressed={isMuted}
   712→          >
   713→            {isMuted ? (
   714→              <VolumeX className="w-5 h-5" />
   715→            ) : (
   716→              <Volume2 className="w-5 h-5" />
   717→            )}
   718→          </Button>
   719→          <Button
   720→            variant="ghost"
   721→            size="icon"
   722→            onClick={handleVoiceToggle}
   723→            aria-label={mode === 'voice' ? 'Passa al testo' : 'Passa alla voce'}
   724→            aria-pressed={mode === 'voice'}
   725→            className={cn(mode === 'voice' && 'bg-red-100 text-red-600')}
   726→          >
   727→            {mode === 'voice' ? (
   728→              <MicOff className="w-5 h-5" />
   729→            ) : (
   730→              <Mic className="w-5 h-5" />
   731→            )}
   732→          </Button>
   733→          <Button
   734→            size="icon"
   735→            onClick={handleSend}
   736→            disabled={!inputValue.trim() || isLoading}
   737→            aria-label="Invia messaggio"
   738→            className="bg-accent-themed hover:bg-accent-themed/90"
   739→          >
   740→            <Send className="w-5 h-5" aria-hidden="true" />
   741→          </Button>
   742→        </div>
   743→      </div>
   744→    </div>
   745→  );
   746→}
