    89→/**
    90→ * Conversation summary from DB (used for context, not full message restoration).
    91→ */
    92→interface ConversationSummary {
    93→  id: string;
    94→  maestroId: string;
    95→  title: string;
    96→  summary: string | null;
    97→  keyFacts: string[] | null;
    98→  topics: string[];
    99→  messageCount: number;
   100→  lastMessageAt: string | null;
   101→}
   102→
   103→/**
   104→ * Load conversation summaries from the database (not full messages).
   105→ * We use summaries for context instead of restoring entire conversations.
   106→ */
   107→async function loadConversationSummariesFromDB(): Promise<ConversationSummary[]> {
   108→  try {
   109→    const response = await fetch('/api/conversations?limit=20&active=true');
   110→
   111→    // 401 = no user cookie yet (first visit), not an error
   112→    if (response.status === 401) {
   113→      return [];
   114→    }
   115→
   116→    if (!response.ok) {
   117→      logger.warn('Conversations API returned error', { status: response.status });
   118→      return [];
   119→    }
   120→
   121→    const data = await response.json();
   122→
   123→    // API might return error object instead of array
   124→    if (!Array.isArray(data)) {
   125→      if (data.error) {
   126→        logger.warn('Conversations API error', { error: data.error });
   127→      }
   128→      return [];
   129→    }
   130→
   131→    return data;
   132→  } catch (error) {
   133→    // Network error or JSON parse error
   134→    logger.warn('Error loading conversation summaries', { error: String(error) });
   135→    return [];
   136→  }
   137→}
