   307→/**
   308→ * Creates an ActiveCharacter from character data.
   309→ */
   310→function createActiveCharacter(
   311→  character: MaestroFull | SupportTeacher | BuddyProfile,
   312→  type: CharacterType,
   313→  profile: ExtendedStudentProfile
   314→): ActiveCharacter {
   315→  let greeting: string;
   316→  let systemPrompt: string;
   317→  let voiceInstructions: string;
   318→
   319→  if (type === 'buddy') {
   320→    const buddy = character as BuddyProfile;
   321→    greeting = buddy.getGreeting(profile);
   322→    systemPrompt = buddy.getSystemPrompt(profile);
   323→    voiceInstructions = buddy.voiceInstructions;
   324→  } else if (type === 'coach') {
   325→    const coach = character as SupportTeacher;
   326→    greeting = coach.greeting;
   327→    systemPrompt = coach.systemPrompt;
   328→    voiceInstructions = coach.voiceInstructions;
   329→  } else {
   330→    const maestro = character as MaestroFull;
   331→    greeting = maestro.greeting;
   332→    systemPrompt = maestro.systemPrompt;
   333→    voiceInstructions = '';
   334→  }
   335→
   336→  return {
   337→    type,
   338→    id: character.id,
   339→    name: character.name,
   340→    character,
   341→    greeting,
   342→    systemPrompt,
   343→    color: character.color,
   344→    voice: 'voice' in character ? character.voice : 'alloy',
   345→    voiceInstructions,
   346→  };
   347→}
   348→
   349→/**
   350→ * Save current messages to character's conversation bucket.
   351→ */
   352→function saveCurrentConversation(
   353→  state: ConversationFlowState
   354→): Record<string, CharacterConversation> {
   355→  if (!state.activeCharacter || state.messages.length === 0) {
   356→    return state.conversationsByCharacter;
   357→  }
   358→
   359→  const characterId = state.activeCharacter.id;
   360→  const existingConvo = state.conversationsByCharacter[characterId];
   361→
   362→  return {
   363→    ...state.conversationsByCharacter,
   364→    [characterId]: {
   365→      characterId,
   366→      characterType: state.activeCharacter.type,
   367→      characterName: state.activeCharacter.name,
   368→      messages: state.messages,
   369→      lastMessageAt: new Date(),
   370→      conversationId: existingConvo?.conversationId,
   371→    },
   372→  };
   373→}
   374→
   375→/**
   376→ * Load messages for a character from their conversation bucket.
   377→ */
   378→function loadConversationMessages(
   379→  conversationsByCharacter: Record<string, CharacterConversation>,
   380→  characterId: string
   381→): FlowMessage[] {
   382→  const convo = conversationsByCharacter[characterId];
   383→  return convo?.messages || [];
   384→}
   385→
   386→export const useConversationFlowStore = create<ConversationFlowState>()(
   387→  (set, get) => ({
   388→      mode: 'idle',
   389→      isActive: false,
   390→      activeCharacter: null,
   391→      messages: [],
   392→      pendingHandoff: null,
   393→      conversationsByCharacter: {},
   394→      sessionId: null,
   395→      sessionStartedAt: null,
   396→      characterHistory: [],
   397→      showRatingModal: false,
   398→      sessionSummary: null,
   399→
   400→      startConversation: (profile) => {
   401→        const coach = getDefaultSupportTeacher();
   402→        const activeCharacter = createActiveCharacter(coach, 'coach', profile);
   403→
   404→        // Check if we have existing conversation with this coach
   405→        const state = get();
   406→        const existingMessages = loadConversationMessages(
   407→          state.conversationsByCharacter,
   408→          coach.id
   409→        );
   410→
   411→        // If no existing messages, start with greeting
   412→        const messages: FlowMessage[] =
   413→          existingMessages.length > 0
   414→            ? existingMessages
   415→            : [
   416→                {
   417→                  id: crypto.randomUUID(),
   418→                  role: 'assistant',
   419→                  content: activeCharacter.greeting,
   420→                  timestamp: new Date(),
   421→                  characterId: activeCharacter.id,
   422→                  characterType: 'coach',
   423→                },
   424→              ];
   425→
   426→        set({
   427→          isActive: true,
   428→          mode: 'text',
   429→          activeCharacter,
   430→          messages,
   431→          sessionId: crypto.randomUUID(),
   432→          sessionStartedAt: new Date(),
   433→          characterHistory: [{ type: 'coach', id: coach.id, timestamp: new Date() }],
   434→          pendingHandoff: null,
   435→        });
   436→      },
   437→
   438→      endConversation: () => {
   439→        // Save current conversation before ending
   440→        const state = get();
   441→        const updatedConversations = saveCurrentConversation(state);
   442→
   443→        // Stop inactivity monitoring
   444→        if (state.sessionId) {
   445→          inactivityMonitor.stopTracking(state.sessionId);
   446→        }
   447→
   448→        set({
   449→          isActive: false,
   450→          mode: 'idle',
   451→          activeCharacter: null,
   452→          messages: [],
   453→          pendingHandoff: null,
   454→          sessionId: null,
   455→          sessionStartedAt: null,
   456→          characterHistory: [],
   457→          conversationsByCharacter: updatedConversations,
   458→          showRatingModal: false,
   459→          sessionSummary: null,
   460→        });
   461→      },
   462→
   463→      endConversationWithSummary: async (conversationId: string, _userId: string) => {
   464→        const state = get();
   465→
   466→        // Stop inactivity monitoring
   467→        inactivityMonitor.stopTracking(conversationId);
   468→
   469→        // Calculate session duration
   470→        const duration = state.sessionStartedAt
   471→          ? Math.round((Date.now() - state.sessionStartedAt.getTime()) / 60000)
   472→          : 0;
   473→
   474→        try {
   475→          // Generate summary
   476→          const result = await generateSummary(conversationId);
   477→
   478→          if (result) {
   479→            set({
   480→              sessionSummary: {
   481→                topics: result.topics,
   482→                summary: result.summary,
   483→                duration,
   484→              },
   485→              showRatingModal: true,
   486→            });
   487→          }
   488→        } catch (error) {
   489→          console.error('Failed to generate summary:', error);
   490→        }
   491→
   492→        // Save conversation
   493→        const updatedConversations = saveCurrentConversation(state);
   494→
   495→        set({
   496→          isActive: false,
   497→          mode: 'idle',
   498→          conversationsByCharacter: updatedConversations,
   499→        });
   500→      },
   501→
   502→      setMode: (mode) => set({ mode }),
   503→
   504→      setShowRatingModal: (show: boolean) => set({ showRatingModal: show }),
   505→
   506→      addMessage: async (message) => {
   507→        const state = get();
   508→        const newMessage: FlowMessage = {
   509→          ...message,
   510→          id: crypto.randomUUID(),
   511→          timestamp: new Date(),
   512→          characterId: message.role === 'assistant' ? state.activeCharacter?.id : undefined,
   513→          characterType: message.role === 'assistant' ? state.activeCharacter?.type : undefined,
   514→        };
   515→
   516→        const newMessages = [...state.messages, newMessage];
   517→
   518→        // Also update the conversation bucket
   519→        const characterId = state.activeCharacter?.id;
   520→        let updatedConversations = state.conversationsByCharacter;
   521→        let conversationId = state.conversationsByCharacter[characterId || '']?.conversationId;
   522→
   523→        if (characterId && state.activeCharacter) {
   524→          // Create conversation in DB if not exists
   525→          if (!conversationId) {
   526→            conversationId = await createConversationInDB(
   527→              characterId,
   528→              state.activeCharacter.type,
   529→              state.activeCharacter.name
   530→            ) || undefined;
   531→          }
   532→
   533→          updatedConversations = {
   534→            ...state.conversationsByCharacter,
   535→            [characterId]: {
   536→              characterId,
   537→              characterType: state.activeCharacter.type,
   538→              characterName: state.activeCharacter.name,
   539→              messages: newMessages,
   540→              lastMessageAt: new Date(),
   541→              conversationId,
   542→            },
   543→          };
   544→
   545→          // Persist message to DB (fire and forget)
   546→          if (conversationId) {
   547→            saveMessageToDB(conversationId, newMessage.role, newMessage.content);
   548→          }
   549→        }
   550→
   551→        set({
   552→          messages: newMessages,
   553→          conversationsByCharacter: updatedConversations,
   554→        });
   555→      },
   556→
   557→      clearMessages: () => {
   558→        const state = get();
   559→        const characterId = state.activeCharacter?.id;
   560→
   561→        // Also clear from conversation bucket
   562→        if (characterId) {
   563→          const { [characterId]: _, ...rest } = state.conversationsByCharacter;
   564→          set({ messages: [], conversationsByCharacter: rest });
   565→        } else {
   566→          set({ messages: [] });
   567→        }
   568→      },
   569→
   570→      routeMessage: (message, profile) => {
   571→        const state = get();
   572→        return routeToCharacter({
   573→          message,
   574→          studentProfile: profile,
   575→          currentCharacter: state.activeCharacter
   576→            ? { type: state.activeCharacter.type, id: state.activeCharacter.id }
   577→            : undefined,
   578→          preferContinuity: true,
   579→        });
   580→      },
   581→
   582→      switchToCharacter: (character, type, profile, _reason) => {
   583→        const state = get();
   584→
   585→        // 1. Save current conversation to its bucket
   586→        const savedConversations = saveCurrentConversation(state);
   587→
   588→        // 2. Create new active character
   589→        const activeCharacter = createActiveCharacter(character, type, profile);
   590→
   591→        // 3. Load existing messages for new character (or start fresh)
   592→        let messages = loadConversationMessages(savedConversations, character.id);
   593→
   594→        if (messages.length === 0) {
   595→          // No existing conversation - add greeting
   596→          messages = [
   597→            {
   598→              id: crypto.randomUUID(),
   599→              role: 'assistant',
   600→              content: activeCharacter.greeting,
   601→              timestamp: new Date(),
   602→              characterId: activeCharacter.id,
   603→              characterType: type,
   604→            },
   605→          ];
   606→        }
   607→
   608→        // 4. Update history
   609→        const newHistory = [
   610→          ...state.characterHistory,
   611→          { type, id: character.id, timestamp: new Date() },
   612→        ];
   613→
   614→        set({
   615→          activeCharacter,
   616→          messages,
   617→          characterHistory: newHistory,
   618→          pendingHandoff: null,
   619→          conversationsByCharacter: savedConversations,
   620→        });
   621→      },
   622→
   623→      switchToCoach: (profile) => {
   624→        const coach = getDefaultSupportTeacher();
   625→        get().switchToCharacter(coach, 'coach', profile);
   626→      },
   627→
   628→      switchToMaestro: (maestro, profile) => {
   629→        get().switchToCharacter(maestro, 'maestro', profile);
   630→      },
   631→
   632→      switchToBuddy: (profile) => {
   633→        const buddy = getBuddyForStudent(profile);
   634→        get().switchToCharacter(buddy, 'buddy', profile);
   635→      },
   636→
   637→      goBack: (profile) => {
   638→        const state = get();
   639→        if (state.characterHistory.length <= 1) {
   640→          return false;
   641→        }
   642→
   643→        // Save current before going back
   644→        const savedConversations = saveCurrentConversation(state);
   645→
   646→        const newHistory = state.characterHistory.slice(0, -1);
   647→        const previous = newHistory[newHistory.length - 1];
   648→
   649→        let character: MaestroFull | SupportTeacher | BuddyProfile | undefined;
   650→
   651→        switch (previous.type) {
   652→          case 'maestro':
   653→            character = getMaestroById(previous.id);
   654→            break;
   655→          case 'coach':
   656→            character = getSupportTeacherById(previous.id as 'melissa' | 'roberto');
   657→            break;
   658→          case 'buddy':
   659→            character = getBuddyById(previous.id as BuddyId);
   660→            break;
   661→        }
   662→
   663→        if (!character) {
   664→          return false;
   665→        }
   666→
   667→        const activeCharacter = createActiveCharacter(character, previous.type, profile);
   668→
   669→        // Load that character's messages
   670→        const messages = loadConversationMessages(savedConversations, previous.id);
   671→
   672→        set({
   673→          activeCharacter,
   674→          messages: messages.length > 0 ? messages : [
   675→            {
   676→              id: crypto.randomUUID(),
   677→              role: 'assistant',
   678→              content: activeCharacter.greeting,
   679→              timestamp: new Date(),
   680→              characterId: activeCharacter.id,
   681→              characterType: previous.type,
   682→            },
   683→          ],
   684→          characterHistory: newHistory,
   685→          pendingHandoff: null,
   686→          conversationsByCharacter: savedConversations,
